import scala.annotation.tailrec

def nums(Array: Array[Long]): Long = {
  var onesIndices = List.empty[Int]
  var twosIndices = List.empty[Int]

  // Collect indices of 1s and 2s
  Array.indices.foreach { i =>
    if (Array(i) == 1) {
      onesIndices = onesIndices :+ i
    } else if (Array(i) == 2) {
      twosIndices = twosIndices :+ i
    }
  }

  // Check if any valid pair exists
  if (onesIndices.isEmpty || twosIndices.isEmpty) {
    return -1L
  }

  var minDiff = Int.MaxValue

  // Iterate through all pairs (i, j) where nums[i] == 1 and nums[j] == 2
  for (i <- onesIndices) {
    for (j <- twosIndices) {
      val diff = Math.abs(i - j)
      if (diff < minDiff) {
        minDiff = diff
      }
    }
  }

  minDiff.toLong
}
