import scala.annotation.tailrec

object Solution {
  /**
    * @param nums The input array containing only 0, 1, and 2.
    * @return The minimum absolute difference between indices i and j such that nums[i] == 1 and nums[j] == 2, or -1 if no such pair exists.
    */
  def nums(nums: Array[Long]): Long = {
    val onesIndices = new java.util.ArrayList[Int]()
    val twosIndices = new java.util.ArrayList[Int]()

    // 1. Collect indices of 1s and 2s
    for (i <- 0 until nums.length) {
      if (nums(i) == 1) {
        onesIndices.add(i)
      } else if (nums(i) == 2) {
        twosIndices.add(i)
      }
    }

    // 2. Check if any valid pair exists
    if (onesIndices.isEmpty || twosIndices.isEmpty) {
      return -1L
    }

    // 3. Find the minimum absolute difference
    var minDiff = Long.MaxValue

    // Iterate over all pairs (i_idx, j_idx) where i_idx is an index of a 1, and j_idx is an index of a 2.
    for (iIdx <- 0 until onesIndices.size) {
      val i = onesIndices.get(iIdx)
      for (jIdx <- 0 until twosIndices.size) {
        val j = twosIndices.get(jIdx)
        val diff = Math.abs(i - j)
        if (diff < minDiff) {
          minDiff = diff
        }
      }
    }

    if (minDiff == Long.MaxValue) {
      // Should not happen if both lists are non-empty, but as a safeguard
      -1L
    } else {
      minDiff
    }
  }
}
